query:
CREATE TABLE `subscriptions` (
	`id` int AUTO_INCREMENT NOT NULL,
	`tenantId` int NOT NULL,
	`plan` enum('free','pro','enterprise') NOT NULL DEFAULT 'free',
	`status` enum('active','trialing','past_due','cancelled','expired') NOT NULL DEFAULT 'trialing',
	`hotmartTransactionId` varchar(255),
	`hotmartSubscriptionId` varchar(255),
	`hotmartProductId` varchar(255),
	`hotmartBuyerEmail` varchar(320),
	`priceInCents` int DEFAULT 9700,
	`trialStartedAt` timestamp,
	`trialEndsAt` timestamp,
	`currentPeriodStart` timestamp,
	`currentPeriodEnd` timestamp,
	`cancelledAt` timestamp,
	`createdAt` timestamp NOT NULL DEFAULT (now()),
	`updatedAt` timestamp NOT NULL DEFAULT (now()) ON UPDATE CURRENT_TIMESTAMP,
	CONSTRAINT `subscriptions_id` PRIMARY KEY(`id`)
);
CREATE INDEX `sub_tenant_idx` ON `subscriptions` (`tenantId`);
CREATE INDEX `sub_hotmart_idx` ON `subscriptions` (`hotmartSubscriptionId`);
CREATE INDEX `sub_status_idx` ON `subscriptions` (`status`);
ALTER TABLE `tenants` MODIFY COLUMN `plan` enum('free','pro','enterprise') NOT NULL DEFAULT 'free';
ALTER TABLE `tenants` ADD `slug` varchar(128);
ALTER TABLE `tenants` ADD `ownerUserId` int;
ALTER TABLE `tenants` ADD `hotmartEmail` varchar(320);
ALTER TABLE `tenants` ADD `freemiumDays` int DEFAULT 365 NOT NULL;
ALTER TABLE `tenants` ADD `freemiumExpiresAt` timestamp;
ALTER TABLE `tenants` ADD `logoUrl` text;

